package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Windows, Linux, and macOS platforms.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Construct ping command with OS-specific arguments
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)
	var avgStr string

	switch runtime.GOOS {
	case "windows":
		// Parse Windows ping output format
		lines := strings.Split(outputStr, "\n")
		for _, line := range lines {
			if strings.Contains(strings.ToLower(line), "average = ") {
				parts := strings.SplitN(line, "=", 2)
				if len(parts) < 2 {
					continue
				}
				avgPart := strings.TrimSpace(parts[1])
				avgStr = strings.TrimSuffix(avgPart, "ms")
				avgStr = strings.TrimSpace(avgStr)
				break
			}
		}
	default:
		// Parse Unix-like (Linux/macOS) ping output format
		lines := strings.Split(outputStr, "\n")
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}

		if statsLine == "" {
			return 0, errors.New("could not find RTT statistics in ping output")
		}

		// Regex to capture average latency (second value in min/avg/max/mdev/stddev line)
		re := regexp.MustCompile(`= ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr = matches[2]
	}

	if avgStr == "" {
		return 0, errors.New("could not find average latency in ping output")
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// Main function for testing purposes
func main() {
	avg, err := MeasureLatency("google.com", 3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

