package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Handles both Linux and macOS ping output formats, and tolerates partial packet loss (returns average of received packets).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without shell to avoid injection risks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Handle execution errors
	if err != nil {
		exitErr, ok := err.(*exec.ExitError)
		if !ok {
			// Non-exit error (e.g., command not found)
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outputStr)
		}

		exitCode := exitErr.ExitCode()
		switch exitCode {
		case 1:
			// Partial or total packet loss - proceed to check if stats exist
		case 2:
			// Fatal error (e.g., unknown host, invalid arguments)
			return 0, fmt.Errorf("ping failed with fatal error: %w (output: %s)", err, outputStr)
		default:
			return 0, fmt.Errorf("ping exited with unexpected code %d: %w (output: %s)", exitCode, err, outputStr)
		}
	}

	// Look for the line containing RTT statistics (works for both Linux and macOS)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output (no packets received?)")
	}

	// Parse stats line to extract average latency
	// Split around equals sign to separate label from values
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) != 2 {
		return 0, errors.New("invalid statistics line format: missing equals sign")
	}

	// Trim whitespace and remove "ms" suffix
	valuesPart := strings.TrimSpace(parts[1])
	valuesPart = strings.TrimSuffix(valuesPart, " ms")

	// Split values by slash to get min/avg/max/mdev or min/avg/max/stddev
	values := strings.Split(valuesPart, "/")
	if len(values) < 3 {
		return 0, errors.New("invalid statistics line format: insufficient values (need min/avg/max)")
	}

	// Average is always the second value (index 1)
	avgStr := values[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w (value: %s)", err, avgStr)
	}

	return avg, nil
}

