import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	var cmd *exec.Cmd

	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	var avg float64
	var parseErr error

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			parseErr = errors.New("could not find average latency in Windows ping output")
			break
		}
		avgStr := matches[1]
		avg, parseErr = strconv.ParseFloat(avgStr, 64)
	default:
		re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			parseErr = errors.New("could not find average latency in Unix ping output")
			break
		}
		avgStr := matches[1]
		avg, parseErr = strconv.ParseFloat(avgStr, 64)
	}

	if parseErr != nil {
		if cmdErr != nil {
			return 0, fmt.Errorf("ping failed: %w; failed to parse output: %w; output: %s", cmdErr, parseErr, outputStr)
		}
		return 0, fmt.Errorf("failed to parse ping output: %w; output: %s", parseErr, outputStr)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil || count <= 0 {
		fmt.Println("Count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

