// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's native ping command and handles cross-platform differences between Unix-like systems and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command with OS-specific arguments
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute command and capture combined stdout/stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// Parse output to extract average latency or detect packet loss
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Handle 100% packet loss case
		if strings.Contains(line, "100% packet loss") ||
			(strings.Contains(line, "Lost = ") && strings.Contains(line, "(100% loss)")) {
			return 0, fmt.Errorf("all packets lost, no latency data available")
		}

		// Parse Unix-like average (Linux/macOS)
		if strings.Contains(line, "rtt min/avg/max/mdev") || strings.Contains(line, "round-trip min/avg/max/stddev") {
			fields := strings.Fields(line)
			if len(fields) < 4 {
				continue
			}
			values := strings.Split(fields[3], "/")
			if len(values) < 2 {
				continue
			}
			avg, err := strconv.ParseFloat(values[1], 64)
			if err == nil {
				return avg, nil
			}
		}

		// Parse Windows average
		if strings.Contains(line, "Average = ") {
			idx := strings.Index(line, "Average = ")
			if idx == -1 {
				continue
			}
			avgPart := line[idx+len("Average = "):]
			// Remove "ms" suffix and any remaining whitespace
			avgPart = strings.TrimSuffix(avgPart, "ms")
			avgPart = strings.TrimSpace(avgPart)
			avg, err := strconv.ParseFloat(avgPart, 64)
			if err == nil {
				return avg, nil
			}
		}
	}

	// If no average found in output
	return 0, fmt.Errorf("failed to parse average latency from output: %s", outputStr)
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		fmt.Println("Error: Count must be a positive integer")
		os.Exit(1)
	}

	// Measure latency and print result
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

