fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Directly execute ping with proper arguments (avoids shell injection risks)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	// Force English output regardless of system locale to ensure consistent parsing
	cmd.Env = append(os.Environ(), "LC_ALL=C")

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Parse average latency using string splitting (more robust than regex)
	// Split into parts before and after the equals sign
	parts := strings.SplitN(statsLine, " = ", 2)
	if len(parts) < 2 {
		return 0, errors.New("invalid RTT statistics line: missing ' = ' separator")
	}

	// Split values part from unit (e.g., "12.34/23.45/34.56/5.67 ms" → ["12.34/23.45/34.56/5.67", "ms"])
	valuesAndUnit := strings.SplitN(parts[1], " ", 2)
	if len(valuesAndUnit) < 2 {
		return 0, errors.New("invalid RTT statistics line: missing unit (ms)")
	}
	if valuesAndUnit[1] != "ms" {
		return 0, fmt.Errorf("unexpected unit in RTT statistics: got %s, expected ms", valuesAndUnit[1])
	}

	// Split into individual values (min/avg/max/mdev)
	values := strings.Split(valuesAndUnit[0], "/")
	if len(values) < 3 {
		return 0, fmt.Errorf("insufficient values in RTT statistics: expected at least 3, got %d", len(values))
	}

	// Parse average value (second element in the split array)
	avgStr := values[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency '%s': %w", avgStr, err)
	}

	return avg, nil
}

