import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outStr := string(output)

	// Check if command failed to execute entirely (not just exit error)
	if err != nil {
		if _, ok := err.(*exec.ExitError); !ok {
			return 0, fmt.Errorf("failed to execute ping command: %w, output: %s", err, outStr)
		}
		// Proceed to parse output even if there was an exit error (e.g., packet loss)
	}

	var avg float64
	var parseErr error

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = (\d+\.?\d*)ms`)
		matches := re.FindStringSubmatch(outStr)
		if len(matches) < 2 {
			parseErr = fmt.Errorf("no average latency found in ping output: %s", outStr)
		} else {
			avg, parseErr = strconv.ParseFloat(matches[1], 64)
		}
	default:
		re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.\d+/(\d+\.\d+)/\d+\.\d+/\d+\.\d+ ms`)
		matches := re.FindStringSubmatch(outStr)
		if len(matches) < 2 {
			parseErr = fmt.Errorf("no average latency found in ping output: %s", outStr)
		} else {
			avg, parseErr = strconv.ParseFloat(matches[1], 64)
		}
	}

	if parseErr != nil {
		if err != nil {
			return 0, fmt.Errorf("ping command exited with error: %w; failed to parse output: %w", err, parseErr)
		}
		return 0, parseErr
	}

	// Return average even if there was packet loss (exit error), as long as average is valid
	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Error: invalid count '%s' (must be an integer)\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

