package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0.0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0.0, errors.New("count must be a positive integer")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0.0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := strings.TrimSpace(string(output))
	var avgStr string

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = (\d+(?:\.\d+)?)ms`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 2 {
			return 0.0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgStr = match[1]
	default:
		re := regexp.MustCompile(`(rtt|round-trip) min/avg/max/(mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 3 {
			return 0.0, errors.New("failed to parse average latency from Unix-like ping output")
		}
		avgStr = match[3]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0.0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go google.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Invalid count: %s must be an integer\n", countStr)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

