package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Handles both Linux (rtt) and macOS (round-trip) ping output formats.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Directly invoke ping with arguments to avoid shell injection and improve security
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	var exitErr *exec.ExitError
	if err != nil {
		if !errors.As(err, &exitErr) {
			// Non-exit error (e.g., command not found, permission denied)
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
		}
		// Exit code 1 means some packets were lost (non-fatal), proceed to parse output
		if exitErr.ExitCode() != 1 {
			// Exit code 2 means fatal error (e.g., host unreachable, invalid arguments)
			return 0, fmt.Errorf("ping failed with fatal error: %w (output: %s)", err, string(output))
		}
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Look for either Linux (rtt) or macOS (round-trip) RTT statistics line
		if (strings.Contains(line, "rtt") || strings.Contains(line, "round-trip")) && strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, fmt.Errorf("could not find RTT statistics in ping output (output: %s)", outputStr)
	}

	// Regex to match both Linux and macOS RTT lines
	// Linux example: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS example: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from stats line: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

// Optional main function for testing
func main() {
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

