package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0.0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0.0, fmt.Errorf("count must be at least 1, got %d", count)
	}

	// Construct ping command with OS-specific arguments
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Unix-like systems (Linux, macOS, BSD, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0.0, fmt.Errorf("ping failed with exit code %d: %s", exitErr.ExitCode(), string(output))
		}
		return 0.0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse output to extract average latency
	var re *regexp.Regexp

	switch runtime.GOOS {
	case "windows":
		// Windows ping output pattern: "Average = Xms" or "Average = X.Yms"
		re = regexp.MustCompile(`Average = ([0-9.]+)ms`)
	default:
		// Unix-like ping output pattern: "rtt min/avg/max/mdev = a/b/c/d ms"
		re = regexp.MustCompile(`rtt min/avg/max/mdev = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)
	}

	matches := re.FindStringSubmatch(string(output))
	if len(matches) < 2 {
		return 0.0, fmt.Errorf("could not parse average latency from ping output:\n%s", string(output))
	}

	// Convert parsed string to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0.0, fmt.Errorf("failed to convert average latency to numeric value: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Parse command line arguments
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	count, err := strconv.Atoi(countStr)
	if err != nil || count < 1 {
		fmt.Println("Error: Ping count must be a positive integer")
		os.Exit(1)
	}

	// Measure latency
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	// Display result
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

