func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, output)
	}

	outputStr := string(output)
	var avg float64

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = (\d+)ms`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 2 {
			return 0, fmt.Errorf("could not find average latency in ping output")
		}
		avgInt, err := strconv.Atoi(match[1])
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		avg = float64(avgInt)
	default:
		re := regexp.MustCompile(`(rtt min/avg/max/mdev|round-trip min/avg/max/stddev) = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 3 {
			return 0, fmt.Errorf("could not find average latency in ping output")
		}
		avg, err = strconv.ParseFloat(match[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Error: invalid count '%s' - must be an integer\n", countStr)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

