package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command with OS-specific flags
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, output)
	}

	outputStr := string(output)
	var avg float64

	// Parse average latency based on OS
	switch runtime.GOOS {
	case "windows":
		// Parse Windows ping output format
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Windows ping output: %s", outputStr)
		}
		avgInt, err := strconv.Atoi(matches[1])
		if err != nil {
			return 0, fmt.Errorf("failed to convert latency to integer: %w", err)
		}
		avg = float64(avgInt)
	default:
		// Parse Unix-like (Linux/macOS) ping output format
		re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.\d+/(\d+\.\d+)/\d+\.\d+/\d+\.\d+ ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Unix ping output: %s", outputStr)
		}
		avg, err = strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to convert latency to float: %w", err)
		}
	}

	return avg, nil
}

// main demonstrates usage of the MeasureLatency function
func main() {
	host := "google.com"
	count := 3

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

