import (
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command (Unix-like systems: Linux/macOS)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Execute command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()

	// Check if command failed completely (no output)
	if err != nil && len(output) == 0 {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse output to extract average latency
	outputStr := string(output)
	var avgStr string
	lines := strings.Split(outputStr, "\n")

	for _, line := range lines {
		// Look for latency statistics lines common in Unix-like ping outputs
		if strings.Contains(line, "rtt min/avg/max/mdev") || strings.Contains(line, "round-trip min/avg/max/stddev") {
			// Split line to get values section
			parts := strings.SplitN(line, "=", 2)
			if len(parts) < 2 {
				continue
			}

			// Extract and split latency values
			valuesPart := strings.TrimSpace(parts[1])
			values := strings.Split(valuesPart, "/")
			if len(values) >= 2 {
				avgStr = strings.TrimSpace(values[1])
				break
			}
		}
	}

	// Check if we found the average value
	if avgStr == "" {
		return 0, fmt.Errorf("could not extract average latency from ping output:\n%s", outputStr)
	}

	// Convert average string to float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	// Parse count argument
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Error: Invalid ping count '%s' - must be an integer\n", countStr)
		os.Exit(1)
	}

	// Measure latency
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Print result
	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

