package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"runtime"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w\nOutput: %s", err, string(output))
	}

	outputStr := string(output)
	var avgStr string

	switch runtime.GOOS {
	case "windows":
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not find average latency in ping output:\n%s", outputStr)
		}
		avgStr = matches[1]
	default:
		reLinux := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		matches := reLinux.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			reMac := regexp.MustCompile(`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
			matches = reMac.FindStringSubmatch(outputStr)
			if len(matches) < 2 {
				return 0, fmt.Errorf("could not find average latency in ping output:\n%s", outputStr)
			}
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency '%s': %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Invalid count: %s. Must be a positive integer.\n", countStr)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", host, count, avgLatency)
}

