package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's native ping command and handles cross-OS differences (Windows vs Unix-like systems).
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build ping command with OS-specific arguments
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, FreeBSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping failed with exit status %d: %w, output: %s", exitErr.ExitCode(), err, string(output))
		}
		return 0, fmt.Errorf("failed to run ping command: %w", err)
	}

	// Parse output to extract average latency
	outputStr := string(output)
	regexPattern := regexp.MustCompile(`(?:avg\/|Average = )([\d.]+)`)
	matches := regexPattern.FindStringSubmatch(outputStr)

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from output: %s", outputStr)
	}

	// Convert parsed string to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency value '%s' to number: %w", matches[1], err)
	}

	return avgLatency, nil
}

// main provides a command-line interface for the latency measurement tool
func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	count, err := strconv.Atoi(countStr)
	if err != nil || count <= 0 {
		fmt.Println("Error: ping count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

