fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Directly execute ping with arguments to avoid shell injection risks
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT/round-trip statistics (supports Linux and macOS)
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		if (strings.Contains(trimmedLine, "rtt") || strings.Contains(trimmedLine, "round-trip")) && 
		   strings.Contains(trimmedLine, "min/avg/max") {
			statsLine = trimmedLine
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT/round-trip statistics in ping output")
	}

	// Extract average latency using regex that supports both Linux and macOS output formats
	// Supported line examples:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 1.234/2.345/3.456/0.123 ms
	// Integer values: rtt min/avg/max/mdev = 12/23/34/5 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/mdev|/stddev)? = \d+(?:\.\d+)?/(\d+(?:\.\d+)?)/\d+(?:\.\d+)?(?:/\d+(?:\.\d+)?)? ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output line: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w (value: %s)", err, avgStr)
	}

	return avg, nil
}

