func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	var avg float64
	var parseErr error

	switch runtime.GOOS {
	case "windows":
		avg, parseErr = parseWindowsPingOutput(outputStr)
	default:
		avg, parseErr = parseUnixPingOutput(outputStr)
	}

	if parseErr == nil {
		return avg, nil
	}

	if err != nil {
		return 0, fmt.Errorf("ping failed: %w, output: %s", err, outputStr)
	}

	return 0, fmt.Errorf("failed to parse ping output: %w, output: %s", parseErr, outputStr)
}

func parseUnixPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max/") {
			parts := strings.SplitN(line, " = ", 2)
			if len(parts) < 2 {
				return 0, fmt.Errorf("missing rtt values")
			}
			rttValues := strings.Split(parts[1], "/")
			if len(rttValues) < 4 {
				return 0, fmt.Errorf("insufficient rtt values")
			}
			avgStr := strings.TrimSpace(rttValues[1])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("invalid average value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("no rtt statistics found in output")
}

func parseWindowsPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "Average = ") {
			parts := strings.SplitN(line, "Average = ", 2)
			if len(parts) < 2 {
				return 0, fmt.Errorf("missing average value")
			}
			avgPart := strings.TrimSpace(parts[1])
			avgStr := strings.TrimSuffix(avgPart, "ms")
			avgStr = strings.TrimSpace(avgStr)
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("invalid average value: %w", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("no average statistics found in output")
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil || count <= 0 {
		fmt.Println("Error: count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

