package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var timeRegex = regexp.MustCompile(`time=([0-9]+(?:\.[0-9]+)?) ?ms`)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0.0, errors.New("count must be a positive integer")
	}
	if host == "" {
		return 0.0, errors.New("host cannot be empty")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			switch exitErr.ExitCode() {
			case 1:
				return 0.0, errors.New("no responses received from host")
			case 2:
				return 0.0, fmt.Errorf("ping command failed: %s", string(output))
			}
		}
		return 0.0, fmt.Errorf("failed to execute ping: %w", err)
	}

	matches := timeRegex.FindAllStringSubmatch(string(output), -1)
	if len(matches) == 0 {
		return 0.0, errors.New("could not extract latency values from ping output")
	}

	var total float64
	for _, match := range matches {
		latency, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			return 0.0, fmt.Errorf("invalid latency value '%s': %w", match[1], err)
		}
		total += latency
	}

	average := total / float64(len(matches))
	return average, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: latency <host> <count>")
		fmt.Println("Example: latency google.com 5")
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Error: Invalid count '%s' - must be an integer\n", countStr)
		os.Exit(1)
	}

	averageLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, averageLatency)
}

