package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Even if some packets are lost, it returns the average latency of successful pings (if available).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly with arguments to avoid shell injection and unnecessary shell overhead
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Look for the line containing RTT statistics
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		// No stats line found: return error with context
		if err != nil {
			return 0, fmt.Errorf("ping failed and no RTT statistics found: %w (output: %s)", err, outputStr)
		}
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex that handles:
	// - Lines with or without mdev (standard vs simplified output)
	// - Integer or decimal values for min/avg/max/mdev
	// Example lines:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// rtt min/avg/max = 12/23/34 ms
	re := regexp.MustCompile(`rtt min/avg/max(?:/mdev)? = \d+(?:\.\d+)?/([\d.]+)/\d+(?:\.\d+)?(?:/\d+(?:\.\d+)?)? ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	// Return average even if there was packet loss (ping returns non-zero exit code for partial loss)
	return avg, nil
}

// Main function for testing the MeasureLatency utility
func main() {
	if len(os.Args) < 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count value: %s (must be positive integer)\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.3f ms\n", host, avgLatency)
}

