package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency executes ping command to specified host multiple times and returns average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Construct ping command arguments based on operating system
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute ping command and capture output
	cmd := exec.Command("ping", args...)
	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}
	outputStr := string(output)

	// Compile appropriate regex pattern for parsing average latency
	var re *regexp.Regexp
	var regexErr error
	switch runtime.GOOS {
	case "windows":
		re, regexErr = regexp.Compile(`Average\s+=\s+([0-9.]+)ms`)
	default:
		re, regexErr = regexp.Compile(`(rtt|round-trip)\s+min/avg/max/(mdev|stddev)\s+=\s+([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s+ms`)
	}

	if regexErr != nil {
		return 0, fmt.Errorf("failed to compile regex: %w", regexErr)
	}

	// Find average latency value in output
	matches := re.FindStringSubmatch(outputStr)
	if matches == nil {
		return 0, fmt.Errorf("could not extract average latency from ping output")
	}

	// Extract average value string based on OS
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		avgStr = matches[1]
	default:
		avgStr = matches[4] // Group 4 contains the average value in Unix-like output
	}

	// Convert string average to float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	// Parse count parameter
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Error: Invalid count '%s' - must be an integer\n", countStr)
		os.Exit(1)
	}

	// Measure latency
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Display result
	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avgLatency)
}

