func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w, output: %s", err, string(output))
	}

	var avgStr string
	switch runtime.GOOS {
	case "windows":
		winRegex := regexp.MustCompile(`Average = (\d+\.?\d*)ms`)
		matches := winRegex.FindStringSubmatch(string(output))
		if len(matches) < 2 {
			return 0, errors.New("could not extract average latency from Windows ping output")
		}
		avgStr = matches[1]
	default:
		unixRegex := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.\d+/(\d+\.\d+)/\d+\.\d+/\d+\.\d+ ms`)
		matches := unixRegex.FindStringSubmatch(string(output))
		if len(matches) < 2 {
			return 0, errors.New("could not extract average latency from Unix ping output")
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Invalid count: %s. Must be a positive integer.\n", countStr)
		os.Exit(1)
	}

