// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It handles cross-platform differences in the ping command and output format.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	// Build ping command arguments based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture combined stdout/stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping failed with exit code %d: %s", exitErr.ExitCode(), string(output))
		}
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse output to extract average latency
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		// Regex to match Windows ping average line: "Average = Xms" or "Average = X.Yms"
		re := regexp.MustCompile(`Average = (\d+(?:\.\d+)?)ms`)
		match := re.FindStringSubmatch(string(output))
		if len(match) < 2 {
			return 0, errors.New("could not extract average latency from Windows ping output")
		}
		avgStr = match[1]
	default:
		// Regex to match Unix-like ping average line (Linux/macOS)
		// Matches lines like: "rtt min/avg/max/mdev = 0.1/0.2/0.3/0.04 ms" or "round-trip min/avg/max/stddev = ..."
		re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		match := re.FindStringSubmatch(string(output))
		if len(match) < 2 {
			return 0, errors.New("could not extract average latency from Unix ping output")
		}
		avgStr = match[1]
	}

	// Convert average string to float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage: Run with "go run main.go <host> <count>" or use defaults
	var host string
	var count int
	var err error

	switch len(os.Args) {
	case 3:
		host = os.Args[1]
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Printf("Error: Invalid count value '%s' (must be an integer)\n", os.Args[2])
			os.Exit(1)
		}
	default:
		// Default values if no arguments are provided
		host = "8.8.8.8"
		count = 4
		fmt.Printf("Using default host: %s, count: %d\n", host, count)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

