package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is designed for Unix-like systems (Linux, macOS, BSD) where ping uses the -c flag for count.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly without shell to avoid injection risks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Split the stats line to extract average latency
	// Split on " = " to separate the label part from the value part
	parts := strings.SplitN(statsLine, " = ", 2)
	if len(parts) != 2 {
		return 0, errors.New("invalid RTT statistics line format: missing ' = ' separator")
	}

	valuePart := parts[1]

	// Remove the " ms" suffix (trim exact suffix first, then fallback to splitting on space)
	if strings.HasSuffix(valuePart, " ms") {
		valuePart = strings.TrimSuffix(valuePart, " ms")
	} else {
		// Fallback: split on first space to separate value from unit
		spaceParts := strings.SplitN(valuePart, " ", 2)
		if len(spaceParts) < 1 {
			return 0, errors.New("invalid RTT statistics line format: missing value part")
		}
		valuePart = spaceParts[0]
	}

	// Split value part by '/' to get min/avg/max/mdev values
	valueSegments := strings.Split(valuePart, "/")
	if len(valueSegments) < 3 {
		return 0, errors.New("invalid RTT statistics line format: insufficient values (expected at least min/avg/max)")
	}

	// Extract average value (second segment, index 1)
	avgStr := strings.TrimSpace(valueSegments[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w (value: %q)", err, avgStr)
	}

	return avg, nil
}

// Optional main function for testing purposes
func main() {
	avg, err := MeasureLatency("google.com", 3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

